int cube[2][2][2] = {
  { {1, 2}, {3, 4} },
  { {5, 6}, {7, 8} }
};
int main(void) {
  int i;
  int j;
  int k;
  int sum;
  sum = 0;
  for (i = 0; i < 2; i++) {
    for (j = 0; j < 2; j++) {
      for (k = 0; k < 2; k++) {
        sum += cube[i][j][k];
      }
    }
  }
  return sum;
}

int rowsums(int a[][3], int rows) {
  int i;
  int j;
  int total;
  total = 0;
  for (i = 0; i < rows; i++) {
    for (j = 0; j < 3; j++) {
      total += a[i][j];
    }
  }
  return total;
}
int main(void) {
