int main(void)
{
  int a[6];
  int *p;
  int *q;
  int count;
  int i;

  for (i = 0; i < 6; i++) {
    a[i] = i * i;
  }
  p = &a[1];
  q = &a[5];
  count = 0;
  while (p < q) {
    count = count + *p;
    p++;
  }
  return count;
}

