#define ROWS 4
#define COLS 3
#define SIZE (ROWS * COLS)
int main(void) {
  int grid[ROWS][COLS];
  int i;
  int sum;
  for (i = 0; i < SIZE; i++) {
    grid[i / COLS][i % COLS] = i;
  }
  sum = 0;
  for (i = 0; i < ROWS; i++) {
    sum += grid[i][COLS - 1];
  }
  return sum + SIZE;
}

